import java.net.*;
import java.io.*;
import org.json.JSONObject;

public class Main {
  public static void main(String[] args) throws Exception {
    URL url = new URL("https://demo.openimis.org/api/api_fhir_r4/login/");
    HttpURLConnection conn = (HttpURLConnection) url.openConnection();
    conn.setRequestMethod("POST");
    conn.setRequestProperty("Content-Type", "application/json");
    conn.setDoOutput(true);

    JSONObject data = new JSONObject();
    data.put("username", "your_username");
    data.put("password", "your_password");
    try(OutputStream os = conn.getOutputStream()) {
      os.write(data.toString().getBytes());
    }

    BufferedReader in = new BufferedReader(new InputStreamReader(conn.getInputStream()));
    String inputLine;
    StringBuilder content = new StringBuilder();
    while ((inputLine = in.readLine()) != null) {
      content.append(inputLine);
    }
    in.close();
    conn.disconnect();

    JSONObject result = new JSONObject(content.toString());
    System.out.println("Token: " + result.getString("token"));
    System.out.println("Expires: " + result.getInt("exp"));
  }
}

