// Step 1: Authenticate
const loginResponse = await fetch('https://demo.openimis.org/api/api_fhir_r4/login/', {
  method: 'POST',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({
    username: 'your_username',
    password: 'your_password'
  })
});

const { token } = await loginResponse.json();

// Step 2: Query patient
const patientResponse = await fetch(
  'https://demo.openimis.org/api/api_fhir_r4/Patient/01EEDC6C-436C-465F-86C2-6FF68644D751/',
  {
    headers: { 'Authorization': `Bearer ${token}` }
  }
);

const patient = await patientResponse.json();
console.log('Patient:', patient.name[0].given[0], patient.name[0].family);
console.log('Gender:', patient.gender);
console.log('Birth Date:', patient.birthDate);
